CREATE TABLE question (id INT auto_increment NOT NULL PRIMARY KEY, question TEXT, answer TEXT, update_time DATETIME DEFAULT CURRENT_TIMESTAMP, chat_id INT NOT NULL, author_id INT NOT NULL);
CREATE TABLE context (id INT NOT NULL PRIMARY KEY, content TEXT, tags TEXT);
CREATE TABLE email_captcha (id INT NOT NULL auto_increment, email VARCHAR(100), captcha VARCHAR(100), primary key(id), create_time DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE user (id INT AUTO_INCREMENT PRIMARY KEY, username VARCHAR(100) NOT NULL, password VARCHAR(200) NOT NULL, email VARCHAR(100) NOT NULL UNIQUE, join_time DATETIME DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE chat (id INT AUTO_INCREMENT NOT NULL PRIMARY KEY, chatname TEXT, create_time DATETIME DEFAULT CURRENT_TIMESTAMP, update_time DATETIME DEFAULT CURRENT_TIMESTAMP, author_id INT NOT NULL);
